        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Invalid argument provided"})

      {:error, %{output: output, exit_code: exit_code}} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{
          status: "error",
          message: "Command failed",
          output: output,
          exit_code: exit_code
        })

      {:error, reason} ->
        conn
